vsetvli x0, x5, e32, m1, tu, mu
la x4, vd_random_base_071                         # Load address of desired value
vle32.v v9, (x4)                                  # Load desired value from memory into v9
la x18, custom_flag_nv_sew32                      # Load address of desired value
vle32.v v7, (x18)                                 # Load desired value from memory into v7
LA(x2, scratch)
LI(x3, 0x7f800001)                                # load x3 with value 0x7f800001
sw x3, 0(x2)                                      # store 0x7f800001 in memory
flw f5, 0(x2)                                     # load 0x7f800001 from memory into f5
Vf32_vmflt_vf_cg_cp_custom_vfp_flags_nv_duplicate_3:
vmflt.vf v9, v7, f5
csrr x22, fcsr                                    # save fcsr into x22 for signature
RVTEST_SIGUPD(x1, x5, x4, x22, Vf32_vmflt_vf_cg_cp_custom_vfp_flags_nv_duplicate_3, test_569_str)# store x22 in signature
vsetivli x0, 1, e8, m1, tu, mu                    # set SEW=8, LMUL=1, VL=1 before signature check
# RVTEST_SIGUPD_V(_CMP, _SIG_PTR, _LINK_REG, _TEMP_REG, _VTMP, _MTMP, _SEW, _OFFSET, _VREG, _INST_PTR, _STR_PTR)
RVTEST_SIGUPD_V(vmxor.mm, x1, x5, x4, v28, v5, 8, 8, v9, Vf32_vmflt_vf_cg_cp_custom_vfp_flags_nv_duplicate_3, test_569_str)# Check if v9 contains the expected result. x1 is the signature ptr, x5 is the link ptr, x4 is a temp reg.

